import Foundation

class HTTPClient {
    private let session: URLSession
    
    init() {
        let configuration = URLSessionConfiguration.default
        configuration.waitsForConnectivity = true
        self.session = URLSession(configuration: configuration)
    }
    
    func request(_ url: URL, method: String, completion: @escaping (Data?, Error?) -> Void) {
        var request = URLRequest(url: url)
        request.httpMethod = method
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(nil, error)
            } else {
                completion(data, nil)
            }
        }
        
        task.resume()
    }
    
    func connectToCloudAPI(endpoint: String, method: String, completion: @escaping (Data?, Error?) -> Void) {
        guard let url = URL(string: "https://api.example.com/\(endpoint)") else { return }
        request(url, method: method, completion: completion)
    }
    
    func connectToLocalDevice(ipAddress: String, endpoint: String, method: String, useHTTPS: Bool, completion: @escaping (Data?, Error?) -> Void) {
        let scheme = useHTTPS ? "https" : "http"
        guard let url = URL(string: "\(scheme)://\(ipAddress)/\(endpoint)") else { return }
        request(url, method: method, completion: completion)
    }
}

